In 2026, the greatest number of dog poop related service requests have come from Manhattan Community Districts 10 and 12. Interestingly, a few Community Districts (1, 2, 5) have had very few in comparison.
Visually:


Code
suppressMessages(
comDist &lt;- read_sf("https://services5.arcgis.com/GfwWNkhOj9bNBqoJ/arcgis/rest/services/NYC_Community_Districts/FeatureServer/0/query?where=1=1&outFields=*&outSR=4326&f=pgeojson") |&gt; 
  st_make_valid() |&gt; 
  filter(BoroCD &lt; 200) |&gt; 
  mutate(community_board = paste0(
    str_sub(as.character(BoroCD), -2),
    " MANHATTAN"
  )) |&gt; 
  left_join(dog_poop_complaints_2026_by_cb) |&gt; 
  mutate(
    tooltip_html = glue(
      "&lt;b&gt;Community Board:&lt;/b&gt; {community_board}&lt;br&gt;",
      "&lt;b&gt;Service requests:&lt;/b&gt; {complaints_2026}"
    )
  )
)

maplibre(style = carto_style("positron")) |&gt; 
  fit_bounds(comDist) |&gt; 
  add_fill_layer(
    id = "Community Districts",
    source = comDist,
    fill_color = interpolate(
      column = "complaints_2026",
      values = c(
        min(comDist$complaints_2026),
        max(comDist$complaints_2026)
      ),
      stops = c("#fff5f0", "#ef3b2c")
    ),
    fill_opacity = 0.7,
    tooltip = "tooltip_html"
  ) |&gt; 
  add_circle_layer(
    id = "Service Requests",
    source = dog_poop_complaints_2026,
    circle_color = "#7f7f7f",
    circle_stroke_color = "#cccccc",
    circle_radius = 5,
    circle_stroke_width = 1
  )
